public class debug_overlap {
    public static void main(String[] args) {
        // Debug the specific London autumn transition issue
        DateTimeZone london = DateTimeZone.forID("Europe/London");

        System.out.println("Testing the London overlap issue:");
        System.out.println("Time: 2011-10-30 01:15 (should be BST +01:00)");

        // Before the transition (BST)
        DateTime beforeTransition = new DateTime(2011, 10, 30, 0, 30, 0, london);
        System.out.println("Before transition (00:30): " + beforeTransition + 
                          ", offset: " + (london.getOffset(beforeTransition.getMillis()) / 3600000));

        // After the transition (GMT)
        DateTime afterTransition = new DateTime(2011, 10, 30, 2, 30, 0, london);
        System.out.println("After transition (02:30): " + afterTransition + 
                          ", offset: " + (london.getOffset(afterTransition.getMillis()) / 3600000));

        // The problematic time
        DateTime overlapTime = new DateTime(2011, 10, 30, 1, 15, london);
        System.out.println("During overlap (01:15): " + overlapTime + 
                          ", offset: " + (london.getOffset(overlapTime.getMillis()) / 3600000));

        // The transition time itself
        long transitionTime = london.nextTransition(london.previousTransition(
            new DateTime(2011, 10, 30, 12, 0, 0, DateTimeZone.UTC).getMillis()));
        if (transitionTime != Long.MAX_VALUE) {
            DateTime trans = new DateTime(transitionTime, london);
            System.out.println("Transition occurs at: " + trans + 
                              ", offset before transition: " + 
                              (london.getStandardOffset(transitionTime - 1) != london.getOffset(transitionTime - 1) ? 
                               "DST" : "standard"));
        }

        System.out.println("\nDebug transition times around 2011-10-30:");
        for (int i = 0; i <= 120; i += 15) {
            long time = new DateTime(2011, 10, 30, 0, i, 0, DateTimeZone.UTC).getMillis();
            DateTime dt = new DateTime(time, london);
            System.out.println("UTC " + new DateTime(time, DateTimeZone.UTC) + 
                             " -> Local " + dt + 
                             ", offset: " + (london.getOffset(dt.getMillis()) / 3600000));
        }
    }
}

