public class trace_convert {
    public static void main(String[] args) {
        DateTimeZone london = DateTimeZone.forID("Europe/London");

        System.out.println("Testing convertLocalToUTC directly for Europe/London overlap:");

        // Create local time 2011-10-30T01:15:00 as milliseconds in the local timezone
        // This is done by creating the time as if it were UTC and then applying the zone
        long localInstant = new DateTime(2011, 10, 30, 1, 15, 0, DateTimeZone.UTC).getMillis();
        System.out.println("Processing localInstant: " + localInstant + 
                          " (represents 2011-10-30T01:15:00 local time)");

        // Call the convertLocalToUTC method to see the internal logic
        try {
            // For this direct method test, I'll calculate what the method would do
            int offsetLocal = london.getOffset(localInstant);
            System.out.println("offsetLocal = getOffset(localInstant) = " + offsetLocal + 
                              " (" + (offsetLocal/3600000) + " hours)");

            long estimatedUTC = localInstant - offsetLocal;
            System.out.println("estimatedUTC = localInstant - offsetLocal = " + estimatedUTC);

            int offset = london.getOffset(estimatedUTC);
            System.out.println("offset = getOffset(estimatedUTC) = " + offset + 
                              " (" + (offset/3600000) + " hours)");

            System.out.println("offsetLocal != offset ? " + (offsetLocal != offset));

            if (offsetLocal != offset) {
                System.out.println("Would enter offset difference handling...");

                // Simulate the transition checks
                long nextLocal = london.nextTransition(localInstant - offsetLocal);
                if (nextLocal == (localInstant - offsetLocal)) {
                    nextLocal = Long.MAX_VALUE;
                }
                long nextAdjusted = london.nextTransition(localInstant - offset);
                if (nextAdjusted == (localInstant - offset)) {
                    nextAdjusted = Long.MAX_VALUE;
                }

                System.out.println("nextLocal: " + nextLocal);
                System.out.println("nextAdjusted: " + nextAdjusted);
                System.out.println("nextLocal != nextAdjusted (gap)? " + (nextLocal != nextAdjusted));

                if (nextLocal != nextAdjusted) {
                    System.out.println("This would be detected as a gap");
                } else {
                    System.out.println("This would be detected as an overlap - using offsetLocal");
                }
            } else {
                System.out.println("No offset difference - would use offset value as is");
            }

        } catch (Exception e) {
            System.out.println("Exception: " + e.getMessage());
        }
    }
}

